from typing import Set, List, Optional, Iterable

from geosat.cloud import PointCloud

from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata


class ResetClassifier(Classifier):
    """This classifier resets the classification field
    of the point cloud to the integer value assigned to
    the "unclassified" class. The class to use can be customized
    with the ``output_class`` option.
    """

    def __init__(
        self, stage_name: Optional[str] = None, output_class: str = "unclassified"
    ) -> None:
        super().__init__(stage_name)
        self.output_class = output_class

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "output_class",
                description="The class to use to reset the classification field",
                type_cast=str,
                required=False,
            )
        ]

    def input_classes(self) -> Set[str]:
        return set()

    def output_classes(self) -> Set[str]:
        return {self.output_class}

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        cloud.classification[:] = pipeline_metadata.classification_codes[
            self.output_class
        ]

        return (cloud,)
